Hi, I tried to create small Self-contained .net core application:
Program.cs:
```
public class Program
    {
        public static void Main(string[] args)
        {
            var urls = File.ReadAllLines("urls.txt");
            Console.WriteLine("How many iterations need?");
            var ns = Console.ReadLine();
            if (!int.TryParse(ns, out int n))
                n = 1;

            for (var i = 0; i < n; i++)
            {
                foreach (var url in urls)
                {
                    MakeRequest(url);
                }
                Console.WriteLine();
            }
            Console.WriteLine("Done. Press any key.");
            Console.ReadKey();
        }

        private static void MakeRequest(string url)
        {
            var sw = new Stopwatch();
            sw.Start();

            HttpStatusCode code;
            int len = 0;
            using (var httpClient = new HttpClient())
            {
                using (var result = httpClient.GetAsync(url).Result)
                {
                    code = result.StatusCode;
                    len = result.Content.ReadAsStringAsync().Result.Length;
                }
            }
            sw.Stop();
            Console.WriteLine("{0, 6} ms. HttpCode: {1, 3}. Url: {3}", sw.ElapsedMilliseconds, code, len, url);
        }
    }
```

